final:
module RefModule (
    input clk,
    input rst_n,
    input ser_in,
    output reg [15:0] par_out
);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or negedge rst_n or posedge dbg_halt) begin
    if (!rst_n)
        par_out <= 16'b0;
    else
        par_out <= {par_out[14:0], ser_in};
end

endmodule
